#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, Y;
        scanf("%lld %lld", &X, &Y);
        long long required = Y * 30LL;
        if (X >= required) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

